      // 当钩爪回到起始位置时，将物体移出游戏
      if (length <= 0) {
        length = 0;
        dropSpeed = 5; // 重置速度
        isDropping = false; // 停止上升
        if (hookedTrash != null) {
          trashItems.remove(hookedTrash);
          hookedTrash = null;
        }
      }
    }
  }

  // 其他方法...
}
